// CREATE — criar registro
$produto = Produto::create([
    'nome'   => 'Camiseta Laravel',
    'preco'  => 89.90,
    'estoque' => 100,
]);

// READ — buscar registros
$todos     = Produto::all();               // todos
$ativo     = Produto::find(1);             // por ID
$primeiro  = Produto::where('ativo', true)->first(); // primeiro resultado
$paginado  = Produto::paginate(15);        // paginado

// UPDATE — atualizar
$produto = Produto::find(1);
$produto->update(['preco' => 79.90]);
// Ou em massa:
Produto::where('estoque', 0)->update(['ativo' => false]);

// DELETE — deletar
$produto = Produto::find(1);
$produto->delete();
// Ou diretamente:
Produto::destroy(1);      // por ID
Produto::destroy([1, 2]); // múltiplos IDs
